
create extension if not exists "pgcrypto";
create table if not exists public.app_settings (id bigint generated by default as identity primary key, key text unique not null, value jsonb not null, updated_at timestamptz default now());
create table if not exists public.categories (id text primary key, name text not null, type text not null, icon text, sort_order int default 0, is_active boolean default true, created_at timestamptz default now());
create table if not exists public.zones (id uuid primary key default gen_random_uuid(), name text not null, fee numeric default 0, eta text, is_active boolean default true, created_at timestamptz default now());
create table if not exists public.stores (id uuid primary key default gen_random_uuid(), name text not null, type text not null, label text, logo_url text, merchant_phone text, rating numeric default 4.5, delivery_time text, status text default 'متاح الآن', is_available boolean default true, is_late boolean default false, created_at timestamptz default now());
create table if not exists public.products (id uuid primary key default gen_random_uuid(), store_id uuid references public.stores(id) on delete set null, category_type text, name text not null, price numeric not null default 0, old_price numeric default 0, image_url text, discount text, is_active boolean default true, created_at timestamptz default now());
create table if not exists public.drivers (id uuid primary key default gen_random_uuid(), name text not null, phone text not null, zone text, availability text default 'available', created_at timestamptz default now());
create table if not exists public.orders (id text primary key, customer_name text not null, customer_phone text not null, customer_address text not null, customer_notes text, replace_option text, zone_id uuid references public.zones(id), zone_name text, eta text, store_id uuid references public.stores(id), store_name text, merchant_phone text, driver_id uuid references public.drivers(id), driver_name text, driver_phone text, items jsonb not null, subtotal numeric not null default 0, delivery numeric not null default 0, total numeric not null default 0, commission numeric default 0, driver_fee numeric default 0, merchant_due numeric default 0, profit numeric default 0, status text default 'Pending Review', zone_review text default 'Pending', payment_status text default 'Unpaid', internal_note text, timeline jsonb default '[]'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.expenses (id uuid primary key default gen_random_uuid(), title text not null, amount numeric not null default 0, note text, created_at timestamptz default now());
alter table public.app_settings enable row level security; alter table public.categories enable row level security; alter table public.zones enable row level security; alter table public.stores enable row level security; alter table public.products enable row level security; alter table public.drivers enable row level security; alter table public.orders enable row level security; alter table public.expenses enable row level security;
do $$ declare r record; begin for r in select schemaname, tablename, policyname from pg_policies where schemaname='public' and tablename in ('app_settings','categories','zones','stores','products','drivers','orders','expenses') loop execute format('drop policy if exists %I on %I.%I', r.policyname, r.schemaname, r.tablename); end loop; end $$;
create policy "public all app_settings" on public.app_settings for all using (true) with check (true);
create policy "public all categories" on public.categories for all using (true) with check (true);
create policy "public all zones" on public.zones for all using (true) with check (true);
create policy "public all stores" on public.stores for all using (true) with check (true);
create policy "public all products" on public.products for all using (true) with check (true);
create policy "public all drivers" on public.drivers for all using (true) with check (true);
create policy "public all orders" on public.orders for all using (true) with check (true);
create policy "public all expenses" on public.expenses for all using (true) with check (true);
insert into public.categories (id,name,type,icon,sort_order,is_active) values ('all','الكل','all','🔥',1,true),('available','متاح الآن','available','✅',2,true),('night','طلبات ليلية','night','🌙',3,true),('super','سوبر ماركت','super','🛒',4,true),('pharma','صيدليات','pharma','💊',5,true),('food','مطاعم','food','🍔',6,true),('fresh','خضار وفاكهة','fresh','🥦',7,true) on conflict (id) do update set name=excluded.name,type=excluded.type,icon=excluded.icon,sort_order=excluded.sort_order,is_active=true;
